import{_ as o,c as d,o as l,a3 as a}from"./chunks/framework.CTM16EAR.js";const g=JSON.parse('{"title":"发布与日常流程","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"dev-log/SOP/RELEASE-dev.md","filePath":"dev-log/SOP/RELEASE-dev.md","lastUpdated":1775699249000}'),i={name:"dev-log/SOP/RELEASE-dev.md"};function t(r,e,c,n,s,p){return l(),d("div",null,e[0]||(e[0]=[a('<h1 id="发布与日常流程" tabindex="-1">发布与日常流程 <a class="header-anchor" href="#发布与日常流程" aria-label="Permalink to &quot;发布与日常流程&quot;">​</a></h1><h2 id="日常流程" tabindex="-1">日常流程 <a class="header-anchor" href="#日常流程" aria-label="Permalink to &quot;日常流程&quot;">​</a></h2><ol><li><p><strong>开发分支</strong></p><ul><li>从最新 <code>dev</code> 开分支：<code>pnpm new:branch feat my-topic</code>（脚本会自动：更新 <code>dev</code> → 基于 <code>dev</code> 创建 <code>feat/my-topic</code>）。</li><li>开发完成后，推到远程：<code>git push -u origin feat/my-topic</code>。</li></ul></li><li><p><strong>合并到 dev（通过 PR）</strong></p><ul><li>创建 PR：<code>gh pr create --base dev --head feat/my-topic</code>。</li><li>在 GitHub 上或命令行确认无误后合并：<code>gh pr merge --squash</code> 或 <code>gh pr merge --merge</code>。</li><li>删除远程分支：<code>git push origin --delete feat/my-topic</code>（可选）。</li></ul></li><li><p><strong>测试</strong></p><ul><li><code>dev</code> 被合并更新后，Cloudflare 会自动为 <code>dev</code> 部署 Preview。</li><li>在 Preview 站自用约 3 天，走完整一天的真实流程。</li></ul></li><li><p><strong>上线（dev → main，通过 PR）</strong></p><ul><li>创建发布 PR：<code>gh pr create --base main --head dev</code>。</li><li>确认 changelog / 差异后，通过 <code>gh pr merge</code> 合并。</li><li>合并后 <code>main</code> 会触发生产站部署，Cloudflare 上线新版本。</li></ul></li></ol><h2 id="仅-dev-才有的功能" tabindex="-1">仅 dev 才有的功能 <a class="header-anchor" href="#仅-dev-才有的功能" aria-label="Permalink to &quot;仅 dev 才有的功能&quot;">​</a></h2><ul><li>在 Cloudflare Pages 的 <strong>Preview</strong> 环境变量里增加：<code>VITE_APP_DEV</code> = <code>true</code>（Production 不配置）。</li><li>代码里用 <code>import.meta.env.VITE_APP_DEV</code> 判断，为真时显示「开发工具」等入口（例如设置页的「清除本地数据」）。</li><li>正式站不设该变量，这些功能不会出现。</li></ul>',5)]))}const h=o(i,[["render",t]]);export{g as __pageData,h as default};
